{"operationName":"FullHistory","variables":{"skip":0,"take":-1},"query":"query FullHistory($skip: Int!, $take: Int!) {
  historyData(skip: $skip, take: $take) {
    totalPurchases
    historicalPurchases {
      id
      relatedSacNumber
      siblings
      dateAndTime {
        ...DateAndTime
        __typename
      }
      status
      eventStatus
      storeName
      totalCost {
        code
        value
        formatted
        __typename
      }
      type
      articles {
        any(skip: 0, take: -1) {
          id
          name
          image {
            optimized
            __typename
          }
          quantity
          description
          itemType
          __typename
        }
        quantity
        __typename
      }
      __typename
    }
    __typename
  }
}

fragment DateAndTime on DateAndTime {
  time
  date
  formattedShortDate
  formattedLongDate
  formattedShortDateTime
  formattedLongDateTime
  formattedWeekDay
  __typename
}"}
